// Create a new user profile in PostgreSQL after Firebase Auth signup
export const createUserProfile = async ({ uid, name, email, role, phone }) => {
  const approved = role !== "doctor"; // Doctors start as unapproved
  await createUser({ uid, name, email, role, phone: phone || "", approved });
};

// Fetch a user's profile by their Firebase UID
export const getUserProfile = async (uid) => {
  try {
    const result = await getUserByUid({ uid });
    const profile = result?.data?.users?.[0] || null;
    if (profile) {
      console.log("[DataConnect] Got user profile:", profile.role);
    }
    return profile;
  } catch (err) {
    console.error("[DataConnect] Error fetching user profile:", err.message);
    return null;
  }
};

