// ──────────────────────────────────────────────────────────────
// APPOINTMENT OPERATIONS
// ──────────────────────────────────────────────────────────────

// Book a new appointment:
//   1. Find and lock the slot (mark as booked)
//   2. Create the appointment record
// Note: Data Connect doesn't support transactions like Firestore,
//       so we do slot check + mark sequentially (optimistic approach)
export const bookAppointment = async ({ doctor, doctorId, date, slot, patient, patientId }) => {
  // 1. Find the slot ID for the requested date + time
  const availableSlots = await fetchAvailableSlots(doctorId, date);
  const matchedSlot = availableSlots.find((s) => s.time === slot && !s.isBooked);

  if (!matchedSlot) {
    throw new Error("This slot is no longer available. Please choose another.");
  }

  // 2. Mark the slot as booked immediately to prevent race conditions
  await markSlotBooked({ slotId: matchedSlot.id });

  try {
    // 3. Calculate token (number of appointments + 1 for that doctor on that date)
    const existing = await fetchDoctorAppointmentsData(doctorId);
    const dayAppts = existing.filter(a => a.date === date && a.status !== "Cancelled");
    const tokenNumber = dayAppts.length + 1;

    // 4. Create the appointment record in PostgreSQL
    const result = await bookAppointmentMutation({
      bookingId: generateBookingId(),
      token: tokenNumber,
      patientId,
      doctorId,
      patientName: patient.name,
      patientAge: Number(patient.age),
      patientGender: patient.gender,
      patientPhone: patient.phone,
      patientEmail: patient.email,
      doctorName: doctor.name,
      doctorSpecialty: doctor.specialty,
      doctorHospital: doctor.hospital,
      doctorFee: Number(doctor.fee),
      date,
      slot,
      reason: patient.reason,
      notes: patient.notes || "",
    });

    return result?.data?.appointment_insert;
  } catch (err) {
    // If appointment creation fails, restore the slot
    await markSlotAvailable({ slotId: matchedSlot.id });
    throw err;
  }
};

