// Fetch admin analytics stats
export const fetchAppointmentStats = async () => {
  try {
    const result = await getAppointmentStats();
    const appointments = result?.data?.appointments || [];
    // Count by status in JavaScript since we can't use SQL aggregates
    const stats = {
      confirmed: appointments.filter(a => a.status === "Confirmed").length,
      completed: appointments.filter(a => a.status === "Completed").length,
      cancelled: appointments.filter(a => a.status === "Cancelled").length,
    };
    console.log("[DataConnect] Appointment stats:", stats);
    return stats;
  } catch (err) {
    console.warn("[DataConnect] fetchAppointmentStats error:", err.message);
    return { confirmed: 0, completed: 0, cancelled: 0 };
  }
};

// ──────────────────────────────────────────────────────────────
// REVIEW OPERATIONS
// ──────────────────────────────────────────────────────────────

// Submit a review and update the doctor's average rating
export const submitReview = async ({ appointmentId, patientId, doctorId, patientName, rating, comment }) => {
  try {
    // 1. Insert the review row
    await submitReviewMutation({ appointmentId, patientId, doctorId, patientName, rating, comment });

    // 2. Mark the appointment as reviewed
    await markAppointmentReviewed({ id: appointmentId });

    // 3. Recalculate doctor's average rating from all reviews
    const allReviews = await getDoctorReviews({ doctorId });
    const reviews = allReviews?.data?.reviews || [];
    if (reviews.length > 0) {
      const avg = reviews.reduce((sum, r) => sum + r.rating, 0) / reviews.length;
      await updateDoctorAverageRating(doctorId, Math.round(avg * 10) / 10, reviews.length);
    }
  } catch (err) {
    console.error("[DataConnect] submitReview error:", err.message);
    throw err;
  }
};

